import React from 'react';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Chip from '@mui/material/Chip';
import Container from '@mui/material/Container';
import FormControl from '@mui/material/FormControl';
import InputLabel from '@mui/material/InputLabel';
import MenuItem from '@mui/material/MenuItem';
import Select from '@mui/material/Select';
import Stack from '@mui/material/Stack';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';

import DataTable, { Column } from '../components/common/DataTable';
import UserAlert from '../components/common/UserAlert';
import { api } from '../services/api';
import type { Category, Network } from '../types/entities';
import { useAppDispatch } from '../store/hooks';
import { showSnackbar } from '../store/slices/uiSlice';
import * as yup from 'yup';

type Row = {
  id: number;
  name: string;
  description: string;
  networkId: number;
  articlesCount: number;
  color: string;
};

const columns: Column<Row>[] = [
  { key: 'id', header: 'ID', render: (r) => r.id },
  {
    key: 'name',
    header: 'Nom',
    render: (r) => (
      <Stack direction="row" spacing={1} alignItems="center">
        <Chip size="small" label="" sx={{ bgcolor: r.color, width: 14, height: 14 }} />
        <span>{r.name}</span>
      </Stack>
    ),
  },
  { key: 'description', header: 'Description', render: (r) => r.description },
  { key: 'articlesCount', header: 'Articles', render: (r) => r.articlesCount },
];

type CategoryFormValues = {
  name: string;
  description: string;
  networkId: number | '';
};

const schema: yup.ObjectSchema<CategoryFormValues> = yup
  .object({
    name: yup.string().required('Nom obligatoire').min(2, 'Nom: min 2 caractĂ¨res'),
    description: yup.string().required('Description obligatoire').min(2, 'Description: min 2 caractĂ¨res'),
    networkId: yup.number().typeError('RĂŠseau obligatoire').required('RĂŠseau obligatoire'),
  })
  .required();

function hashColor(input: string) {
  let h = 0;
  for (let i = 0; i < input.length; i += 1) h = (h * 31 + input.charCodeAt(i)) >>> 0;
  const r = 80 + (h % 120);
  const g = 80 + ((h >> 8) % 120);
  const b = 80 + ((h >> 16) % 120);
  return `rgb(${r}, ${g}, ${b})`;
}

export default function CategoriesList() {
  const dispatch = useAppDispatch();
  const [networks, setNetworks] = React.useState<Network[]>([]);
  const [categories, setCategories] = React.useState<Category[]>([]);
  const [rows, setRows] = React.useState<Row[]>([]);

  const [mode, setMode] = React.useState<'create' | 'edit'>('create');
  const [editingId, setEditingId] = React.useState<number | null>(null);

  const [values, setValues] = React.useState<CategoryFormValues>({ name: '', description: '', networkId: '' });
  const [fieldErrors, setFieldErrors] = React.useState<Record<string, string>>({});
  const [busy, setBusy] = React.useState(false);

  const [error, setError] = React.useState<string | null>(null);

  const refresh = React.useCallback(async () => {
    const data = await api.listCategories();
    setCategories(data);
  }, []);

  React.useEffect(() => {
    let mounted = true;
    setError(null);

    Promise.all([api.listNetworks(), api.listCategories()])
      .then(([nets, cats]) => {
        if (!mounted) return;
        setNetworks(nets);
        setCategories(cats);
      })
      .catch(() => {
        if (!mounted) return;
        setError('Impossible de charger les catĂŠgories / rĂŠseaux.');
      });

    return () => {
      mounted = false;
    };
  }, []);

  React.useEffect(() => {
    setRows(
      categories.map((c) => ({
        id: c.id,
        name: c.name,
        description: c.description,
        networkId: c.networkId,
        articlesCount: c.articlesCount ?? 0,
        color: c.color ?? hashColor(c.name),
      }))
    );
  }, [categories]);

  const validate = async (): Promise<boolean> => {
    try {
      await schema.validate(values, { abortEarly: false });
      setFieldErrors({});
      return true;
    } catch (e) {
      const next: Record<string, string> = {};
      if (e instanceof yup.ValidationError) {
        for (const err of e.inner) {
          if (err.path && !next[err.path]) next[err.path] = err.message;
        }
      }
      setFieldErrors(next);
      return false;
    }
  };

  const startCreate = () => {
    setMode('create');
    setEditingId(null);
    setValues({ name: '', description: '', networkId: '' });
    setFieldErrors({});
    setError(null);
  };

  const startEdit = (c: Category) => {
    setMode('edit');
    setEditingId(c.id);
    setValues({ name: c.name, description: c.description, networkId: c.networkId });
    setFieldErrors({});
    setError(null);
  };

  const submit = async () => {
    setError(null);
    const ok = await validate();
    if (!ok) return;
    if (values.networkId === '') return;

    setBusy(true);
    try {
      if (mode === 'create') {
        await api.createCategory({
          name: values.name,
          description: values.description,
          networkId: values.networkId,
        });
        dispatch(showSnackbar({ severity: 'success', message: 'CatĂŠgorie crĂŠĂŠe.' }));
      } else if (editingId !== null) {
        await api.updateCategory(editingId, {
          name: values.name,
          description: values.description,
          networkId: values.networkId,
        });
        dispatch(showSnackbar({ severity: 'success', message: 'CatĂŠgorie mise Ă  jour.' }));
      }
      await refresh();
      startCreate();
    } catch {
      dispatch(showSnackbar({ severity: 'error', message: "Impossible d'enregistrer la catĂŠgorie." }));
    } finally {
      setBusy(false);
    }
  };

  const remove = async (id: number) => {
    setError(null);
    setBusy(true);
    try {
      await api.deleteCategory(id);
      dispatch(showSnackbar({ severity: 'success', message: 'CatĂŠgorie supprimĂŠe.' }));
      await refresh();
    } catch (e) {
      const msg = e instanceof Error ? e.message : '';
      if (msg.includes('409')) {
        dispatch(showSnackbar({ severity: 'error', message: 'Impossible: catĂŠgorie utilisĂŠe par un article.' }));
      } else {
        dispatch(showSnackbar({ severity: 'error', message: 'Impossible de supprimer la catĂŠgorie.' }));
      }
    } finally {
      setBusy(false);
    }
  };

  const columnsWithActions: Column<Row>[] = [
    ...columns,
    {
      key: 'actions',
      header: 'Actions',
      render: (r) => (
        <Stack direction="row" spacing={1}>
          <Button
            size="small"
            aria-label={`Edit category ${r.id}`}
            onClick={() => {
              const c = categories.find((x) => x.id === r.id);
              if (c) startEdit(c);
            }}
          >
            Edit
          </Button>
          <Button
            size="small"
            color="error"
            aria-label={`Delete category ${r.id}`}
            onClick={() => remove(r.id)}
            disabled={busy}
          >
            Delete
          </Button>
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Stack spacing={2}>
        <Typography variant="h5">CatĂŠgories</Typography>
        {error ? <UserAlert severity="error" message={error} /> : null}

        <Box sx={{ p: 2, bgcolor: 'white', borderRadius: 1, border: '1px solid rgba(0,0,0,0.12)' }}>
          <Stack spacing={2}>
            <Stack direction="row" spacing={2} alignItems="center">
              <Typography variant="subtitle1" sx={{ flexGrow: 1 }}>
                {mode === 'create' ? 'CrĂŠer une catĂŠgorie' : `Modifier la catĂŠgorie #${editingId ?? ''}`}
              </Typography>
              {mode === 'edit' ? (
                <Button aria-label="Nouvelle catĂŠgorie" onClick={startCreate} disabled={busy}>
                  Nouveau
                </Button>
              ) : null}
            </Stack>

            <Stack direction={{ xs: 'column', md: 'row' }} spacing={2}>
              <TextField
                label="Nom"
                value={values.name}
                onChange={(e) => setValues((v) => ({ ...v, name: e.target.value }))}
                error={Boolean(fieldErrors.name)}
                helperText={fieldErrors.name}
                size="small"
                fullWidth
              />
              <FormControl size="small" sx={{ minWidth: 220 }} error={Boolean(fieldErrors.networkId)}>
                <InputLabel id="network-select">RĂŠseau</InputLabel>
                <Select
                  labelId="network-select"
                  label="RĂŠseau"
                  value={values.networkId}
                  onChange={(e) => {
                    const v = String(e.target.value);
                    setValues((cur) => ({ ...cur, networkId: v === '' ? '' : Number(v) }));
                  }}
                >
                  <MenuItem value="">SĂŠlectionner</MenuItem>
                  {networks.map((n) => (
                    <MenuItem key={n.id} value={n.id}>
                      {n.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Stack>

            <TextField
              label="Description"
              value={values.description}
              onChange={(e) => setValues((v) => ({ ...v, description: e.target.value }))}
              error={Boolean(fieldErrors.description)}
              helperText={fieldErrors.description}
              size="small"
              fullWidth
            />

            <Stack direction="row" spacing={1} justifyContent="flex-end">
              <Button aria-label="Enregistrer catĂŠgorie" variant="contained" onClick={submit} disabled={busy}>
                {mode === 'create' ? 'CrĂŠer' : 'Enregistrer'}
              </Button>
            </Stack>
          </Stack>
        </Box>

        <DataTable columns={columnsWithActions} rows={rows} />
      </Stack>
    </Container>
  );
}
